// S7: Context Card - สรุป 5 ฟิลด์หลัก
const input = $input.first().json;

const contextCard = {
  productId: input.product_id || 'CUSTOM',
  productName: input.product_name || input.name,
  category: input.category || 'general',
  priceRange: input.price ? `฿${input.price}` : 'N/A',
  standards: input.standards || '-',
  usp: input.usp || input.selling_point || '',
  region: input.region || input.country || 'Thailand',
  hookType: input.hook_type || 'Story',
  systemPromptKey: input.system_prompt || 'global',
  targetAudience: input.target || 'TikTok creators Thailand',
  language: input.language || 'th'
};

return [{ json: { contextCard, originalInput: input } }];

// S1+S3+S5: Prompt Assembly
const contextCard = $('S7 Context Card').first().json.contextCard;
const kbData = $('S8 Knowledge Base').first().json;

// System Prompts by category
const systemPrompts = {
  food: `คุณเป็นผู้เชี่ยวชาญ Content อาหาร/เครื่องดื่ม เน้น: รสชาติ, สูตรโบราณ, วัตถุดิบคุณภาพ, ความอร่อย น้ำเสียง: กระตุ้นความหิว, อบอุ่น`,
  textile: `คุณเป็นผู้เชี่ยวชาญ Content ผ้าทอ/สิ่งทอ เน้น: ลายผ้า, กระบวนการทอ, สีย้อมธรรมชาติ, ฝีมือช่าง น้ำเสียง: หรูหรา, ภูมิใจในวัฒนธรรม`,
  craft: `คุณเป็นผู้เชี่ยวชาญ Content หัตถกรรม เน้น: ฝีมือทำมือ, ภูมิปัญญาท้องถิ่น, ความเป็นเอกลักษณ์ น้ำเสียง: ชื่นชม, ศิลปะ`,
  herb: `คุณเป็นผู้เชี่ยวชาญ Content สมุนไพร/ความงาม เน้น: สรรพคุณ, ธรรมชาติ, ผลลัพธ์ที่พิสูจน์ได้, ความปลอดภัย น้ำเสียง: น่าเชื่อถือ, วิทยาศาสตร์`,
  global: `คุณเป็นผู้เชี่ยวชาญ Content สินค้าทั่วไป/Tech เน้น: คุณภาพ, ราคาคุ้มค่า, นวัตกรรม น้ำเสียง: ทันสมัย, มั่นใจ`
};

// Hook templates
const hookTemplates = {
  Story: `เริ่มต้นด้วยเรื่องราว/ประวัติ/ตำนาน ที่เชื่อมโยงอารมณ์`,
  Process: `แสดงกระบวนการผลิต/ทำ แบบ ASMR หรือ satisfying`,
  Contrast: `เปรียบเทียบความแตกต่าง หรือความหายาก/พิเศษ`,
  Question: `ตั้งคำถามชวนสงสัย กระตุ้นให้ดูต่อ`,
  Transformation: `แสดง Before/After ผลลัพธ์ที่เห็นได้ชัด`
};

const systemPrompt = systemPrompts[contextCard.systemPromptKey] || systemPrompts.global;
const hookGuide = hookTemplates[contextCard.hookType] || hookTemplates.Story;

// S1: RCCF Prompt
const rccfPrompt = `
[ROLE]
คุณคือ "OpenThai AI" ผู้เชี่ยวชาญสร้าง TikTok Content สำหรับสินค้าไทยและสินค้าทั่วโลก

[CONTEXT]
${systemPrompt}

ข้อมูลสินค้า:
- ชื่อ: ${contextCard.productName}
- หมวด: ${contextCard.category}
- ราคา: ${contextCard.priceRange}
- จุดขาย: ${contextCard.usp}
- ภูมิภาค: ${contextCard.region}
- มาตรฐาน: ${contextCard.standards}

[COMMAND]
สร้าง TikTok Content ประกอบด้วย:
1. Script 30 วินาที (Hook 3วิ + Story 20วิ + CTA 7วิ)
2. Caption (100-150 ตัวอักษร)
3. Hashtags 10 อัน

ใช้ Hook Type: ${contextCard.hookType}
คำแนะนำ: ${hookGuide}

[FORMAT]
ตอบเป็น JSON:
{
  "script": {
    "hook": "...",
    "story": "...",
    "cta": "..."
  },
  "caption": "...",
  "hashtags": ["#...", ...]
}
`;

return [{ json: { prompt: rccfPrompt, contextCard, iteration: 1 } }];

// Parse Claude response
const response = $input.first().json;
const contextCard = $('S1+S3+S5 Prompt Assembly').first().json.contextCard;
const iteration = $('S1+S3+S5 Prompt Assembly').first().json.iteration || 1;

let content;
try {
  const text = response.content[0].text;
  // Extract JSON from response
  const jsonMatch = text.match(/\{[\s\S]*\}/);
  if (jsonMatch) {
    content = JSON.parse(jsonMatch[0]);
  } else {
    content = { error: 'Could not parse JSON', raw: text };
  }
} catch (e) {
  content = { error: e.message, raw: response };
}

return [{ json: { content, contextCard, iteration } }];

