// Parse Critic response
const response = $input.first().json;
const content = $('Parse Response').first().json.content;
const contextCard = $('Parse Response').first().json.contextCard;
const iteration = $('Parse Response').first().json.iteration;

let critique;
try {
  const text = response.content[0].text;
  const jsonMatch = text.match(/\{[\s\S]*\}/);
  if (jsonMatch) {
    critique = JSON.parse(jsonMatch[0]);
  } else {
    critique = { score: 7, error: 'Could not parse' };
  }
} catch (e) {
  critique = { score: 7, error: e.message };
}

return [{ json: { content, critique, contextCard, iteration } }];

// S2: Taste Check + S9: Learning Layer
const content = $input.first().json.content;
const critique = $input.first().json.critique;
const contextCard = $input.first().json.contextCard;
const iteration = $input.first().json.iteration;

// S2: Taste Curation - เทียบกับมาตรฐาน viral content
const tasteScore = Math.min(10, critique.score + (critique.strengths?.length || 0) * 0.5);

// S9: Learning Layer - อธิบายว่าทำไมถึงได้ผล
const learning = {
  hookType: contextCard.hookType,
  whyItWorks: `ใช้ ${contextCard.hookType} Hook ที่เหมาะกับสินค้าประเภท ${contextCard.category}`,
  nextTry: critique.suggestions?.[0] || 'ลองเพิ่ม emotional trigger',
  bestPractice: `สำหรับ ${contextCard.systemPromptKey}: ${critique.strengths?.[0] || 'เน้นจุดขายหลัก'}`
};

const finalOutput = {
  content: content,
  quality: {
    criticScore: critique.score,
    tasteScore: tasteScore,
    iterations: iteration,
    passedQuality: critique.score >= 7,
    strengths: critique.strengths,
    suggestions: critique.suggestions
  },
  learning: learning,
  metadata: {
    productId: contextCard.productId,
    productName: contextCard.productName,
    category: contextCard.category,
    hookType: contextCard.hookType,
    generatedAt: new Date().toISOString()
  }
};

return [{ json: finalOutput }];

// Loop back for iteration (S4)
const content = $input.first().json.content;
const critique = $input.first().json.critique;
const contextCard = $input.first().json.contextCard;
const iteration = $input.first().json.iteration;

// สร้าง prompt ใหม่พร้อม feedback
const improvedPrompt = `
Content เดิม:
${JSON.stringify(content)}

Feedback จาก AI Critic:
- จุดอ่อน: ${critique.weaknesses?.join(', ')}
- คำแนะนำ: ${critique.suggestions?.join(', ')}

กรุณาปรับปรุง Content ให้ดีขึ้นตาม feedback โดยรักษาจุดแข็งเดิม:
- จุดแข็ง: ${critique.strengths?.join(', ')}

ตอบเป็น JSON format เดิม
`;

return [{ json: { prompt: improvedPrompt, contextCard, iteration: iteration + 1 } }];
